// Generate social media posts from blog content
const postData = $input.item.json;
const maxTweetLength = 280;
const maxLinkedInLength = 3000;

// Truncate excerpt for Twitter
function truncateForTwitter(text, url) {
  const urlLength = 23; // Twitter's t.co URL length
  const hashtagLength = 15; // Space for hashtag
  const availableLength = maxTweetLength - urlLength - hashtagLength - 5; // 5 for spaces and ellipsis

  if (text.length <= availableLength) {
    return text;
  }

  return text.substring(0, availableLength - 3) + '...';
}

// Extract hashtags from tags
const hashtags = postData.tags
  .split(', ')
  .filter(tag => tag.length > 0)
  .map(tag => '#' + tag.replace(/\s+/g, ''))
  .slice(0, 3) // Max 3 hashtags
  .join(' ');

// Twitter post (280 characters)
const twitterExcerpt = truncateForTwitter(postData.post_excerpt, postData.post_url);
const twitterPost = `${twitterExcerpt}\n\n${postData.post_url}\n\n${hashtags}`;

// LinkedIn post (more detailed)
const linkedInPost = `${postData.post_title}\n\n${postData.post_excerpt}\n\nRead the full article: ${postData.post_url}\n\n${hashtags} #WebDevelopment #TechBlog`;

// Facebook post
const facebookPost = `${postData.post_title}\n\n${postData.post_excerpt}\n\nRead more: ${postData.post_url}`;

return {
  json: {
    post_id: postData.post_id,
    post_title: postData.post_title,
    post_url: postData.post_url,
    post_slug: postData.post_slug,
    featured_image: postData.featured_image,
    twitter_post: twitterPost,
    linkedin_post: linkedInPost,
    facebook_post: facebookPost,
    hashtags: hashtags
  }
};

